import{_ as e,o as a,c as t,ae as i}from"./chunks/framework.BGHOrOyn.js";const g=JSON.parse('{"title":"OBD GPS Logger Modules","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/obdii-simulators/obd-gps-logger-modules.md","filePath":"obd2/obdii-simulators/obd-gps-logger-modules.md"}'),r={name:"obd2/obdii-simulators/obd-gps-logger-modules.md"};function s(l,o,n,d,h,p){return a(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="obd-gps-logger-modules" tabindex="-1">OBD GPS Logger Modules <a class="header-anchor" href="#obd-gps-logger-modules" aria-label="Permalink to &quot;OBD GPS Logger Modules&quot;">​</a></h1><p>OBD GPS Logger is, in true unix style, a bunch of small programs, each doing a single task [and attempting to do it well]</p><p>Each individual program has its own manpage in the distribution. If you build and &quot;make install&quot;, it will push the manpages into your system appropriately. They&#39;re also available online in a pre-rendered text format, here: <a href="./../../.gitbook/assets/manpages.html">manpages</a></p><h2 id="for-users" tabindex="-1">For users <a class="header-anchor" href="#for-users" aria-label="Permalink to &quot;For users&quot;">​</a></h2><h3 id="obdgpslogger" tabindex="-1">obdgpslogger <a class="header-anchor" href="#obdgpslogger" aria-label="Permalink to &quot;obdgpslogger&quot;">​</a></h3><p>This is the core application - the tool that actually logs data from your car, using OBDII.</p><p>obdgpslogger itself is purely a command-line application, with the intention of being able to run on systems without a display, or as a background daemon for producing data to other front-end applications.</p><h4 id="obdgui" tabindex="-1">obdgui <a class="header-anchor" href="#obdgui" aria-label="Permalink to &quot;obdgui&quot;">​</a></h4><p>For users that want a pointy-clikky way to launch obdgpslogger [with a slightly reduced set of options], obdgui is the way to go.</p><p>The other major difference that obdgui provides is that it has a set of GUI dials, or graphs, for real-time visual reporting similar to your car&#39;s dashboard or other OBDII style applications.</p><h4 id="obdsim" tabindex="-1">obdsim <a class="header-anchor" href="#obdsim" aria-label="Permalink to &quot;obdsim&quot;">​</a></h4><p>For testing without going down to your car, obdgpslogger&#39;s repository contains an ELM327 simulator. obdsim is deliberately kept independant of obdgpslogger at the source level; they share some libraries, but this sim can be used with other OBDII applications.</p><p>One of the main features of this simulator is that it uses plugins for actual number generation. Please visit the page specifically for obdsim for more information</p><h4 id="obd2kml" tabindex="-1">obd2kml <a class="header-anchor" href="#obd2kml" aria-label="Permalink to &quot;obd2kml&quot;">​</a></h4><p>Once you have your logfile, a sqlite database, you will want to convert it to something more human-friendly. One tool for doing this is obd2kml, which exports charts to Google Earth .kml files.</p><p>Multiple charts are drawn in the kml file. One example is a colored chart that shows how fast you were travelling at each point in the trip, and colors the chart based on how efficiently the engine was running at each instant.</p><h4 id="obd2gpx" tabindex="-1">obd2gpx <a class="header-anchor" href="#obd2gpx" aria-label="Permalink to &quot;obd2gpx&quot;">​</a></h4><p>GPX is a common format used by many applications including openstreetmap. obd2gpx is a fairly simple tool that converts obdgpslogger logfiles to gpx</p><p>You can also open gpx files locally using your XML editor of choice</p><h4 id="obd2csv" tabindex="-1">obd2csv <a class="header-anchor" href="#obd2csv" aria-label="Permalink to &quot;obd2csv&quot;">​</a></h4><p>For users that are a little more technically inclined and wish to do their own graphing or analysis, another tool to export logs is obd2csv, which exports to .csv files.</p><p>These files can easily imported into your spreadsheet or statistical package of choice, specifically it&#39;s known to work with Excel or OpenOffice.</p><h4 id="obdlogrepair" tabindex="-1">obdlogrepair <a class="header-anchor" href="#obdlogrepair" aria-label="Permalink to &quot;obdlogrepair&quot;">​</a></h4><p>Occasionally, incidental issues crop up in logfiles. obdlogrepair will check logfiles for internal consistency. It can also be used to change logfiles to work with new versions of the software in the event of schema changes.</p><h4 id="obdftdipty" tabindex="-1">obdftdipty <a class="header-anchor" href="#obdftdipty" aria-label="Permalink to &quot;obdftdipty&quot;">​</a></h4><p>A little proxy to use libftdi and present a posix pseudoterminal in /dev, for when the ftdi-sio kernel module isn&#39;t available [eg, the SheevaPlug]</p><h3 id="for-developers" tabindex="-1">For developers <a class="header-anchor" href="#for-developers" aria-label="Permalink to &quot;For developers&quot;">​</a></h3><h4 id="obdinfo" tabindex="-1">obdinfo <a class="header-anchor" href="#obdinfo" aria-label="Permalink to &quot;obdinfo&quot;">​</a></h4><p>A list of PIDs and information about them, including functions to convert to and from raw OBDII values.</p><h4 id="conf" tabindex="-1">conf <a class="header-anchor" href="#conf" aria-label="Permalink to &quot;conf&quot;">​</a></h4><p>Configuration module common to all obdgpslogger components.</p><p><a href="mailto:chunky@icculus.org" target="_blank" rel="noreferrer">Gary (-;<br> &lt;chunky@icculus.org&gt;</a></p><br>',33)])])}const u=e(r,[["render",s]]);export{g as __pageData,u as default};
